const { execSync } = require('child_process');
try {
  const output = execSync(
    'python main.py --no-hn',
    {
      cwd: 'C:\\Users\\USER\\Documents\\Job Finder',
      timeout: 600000,
      encoding: 'utf8',
      shell: true
    }
  );
  return [{ json: { stdout: output, success: true } }];
} catch(e) {
  return [{ json: { stdout: e.stdout || '', stderr: e.stderr || '', success: false, error: e.message } }];
}

