const stdout = $input.first().json.stdout;
if (!stdout || stdout.trim() === '' || stdout.trim() === '[]') {
  return [{ json: { message: 'No new jobs in last 24 hours' } }];
}
try {
  const jobs = JSON.parse(stdout.trim());
  if (!Array.isArray(jobs) || jobs.length === 0) {
    return [{ json: { message: 'No new jobs in last 24 hours' } }];
  }
  return jobs.map(job => ({ json: job }));
} catch(e) {
  throw new Error('JSON parse failed: ' + e.message + ' | stdout was: ' + stdout.substring(0, 300));
}
